    <style>
        /* General Notification Panel */
        .notification-container {
            width: 100%;
            height: 400px;
            overflow: hidden;
            position: relative;
            background-color: #f8f9fa;
        }

        /* Scrolling Container */
        .scroll-container {
            height: 100%;
            overflow: hidden;
            position: relative;
            padding-left: 10px;
            padding-right: 10px;
        }

        /* Scrolling Text - Notifications */
        #scroll-text {
            display: flex;
            position: relative;
            text-align: left;
            flex-direction: column;
            gap: 10px;
            position: relative;
            top: 0px;
            width: 100%;
            bottom: 0; /* Ensures it starts inside the Notification div */
            animation: my-animation 10s linear infinite;
            animation-play-state: running; /* Default state */
        }

            /* When animation is paused */
            #scroll-text.paused {
                animation-play-state: paused;
            }

            #scroll-text:hover {
                animation-play-state: paused;
            }
        /* Notification Cards */
        .card {
            width: 100%;
            padding: 10px;
            background: white;
            box-shadow: 2px 2px 5px rgba(0, 0, 0, 0.1);
            border-radius: 5px;
        }

        /* Notification Heading */
        .notification-heading {
            font-weight: bold;
            padding: 5px;
            margin-bottom: 5px;
        }

        /* Different Alert Colors */
        .alert {
            color: black;
        }

        .alert-info {
            color: blue;
        }

        .alert-success {
            color: green;
        }

        .alert-warning {
            color: orange;
        }

        /* Scrolling Animation */
        @keyframes my-animation {
            from {
                transform: translateY(400px);
            }

            to {
                transform: translateY(-100%);
            }
        }

        @keyframes scrollUp {
            from {
                top: 0px; /* Start at the bottom of the notification div */
            }

            to {
                top: -100%; /* Move completely up */
            }
        }
    </style>
    <script>
        document.addEventListener("DOMContentLoaded", function () {
            const scrollText = document.getElementById("scroll-text");

            // Add click event listener to pause animation
            scrollText.addEventListener("click", function () {
                if (scrollText.classList.contains("paused")) {
                    scrollText.classList.remove("paused"); // Resume animation
                } else {
                    scrollText.classList.add("paused"); // Pause animation
                }
            });
        });
    </script>
    
